bool ETSChecker::FindPropertyInAssignment(const ir::AstNode *it, const std::string &targetName)
{
    return it->AsClassProperty()->Value()->FindChild([&targetName](ir::AstNode *node) {
        return node->IsIdentifier() && node->AsIdentifier()->Name().Is(targetName) && node->Parent() != nullptr &&
               node->Parent()->IsMemberExpression();
    }) != nullptr;
}

static bool IsExtensionAccessorCallUse(checker::ETSChecker *checker, const ir::MemberExpression *const memberExpr,
                                       ResolvedKind resolvedKind)
{
    return resolvedKind == ResolvedKind::EXTENSION_ACCESSOR &&
           !checker->HasStatus(CheckerStatus::IN_EXTENSION_ACCESSOR_CHECK) &&
           memberExpr->Parent()->IsCallExpression() && memberExpr->Parent()->AsCallExpression()->Callee() == memberExpr;
}

static ResolvedKind DecideResolvedKind(Type *typeOfGlobalFunctionVar)
{
    ES2PANDA_ASSERT(typeOfGlobalFunctionVar != nullptr);
    ES2PANDA_ASSERT(typeOfGlobalFunctionVar->IsETSObjectType() || typeOfGlobalFunctionVar->IsETSFunctionType());
    if (typeOfGlobalFunctionVar->IsETSObjectType()) {
        return ResolvedKind::EXTENSION_FUNCTION;
    }

    if (typeOfGlobalFunctionVar->AsETSFunctionType()->IsExtensionAccessorType()) {
        return ResolvedKind::EXTENSION_ACCESSOR;
    }

    return ResolvedKind::EXTENSION_FUNCTION;
}

void ETSChecker::CheckAnnotationReference(const ir::MemberExpression *memberExpr, const varbinder::LocalVariable *prop)
{
    // Note: there might be a better way to handle annotations
    if (prop != nullptr && prop->Declaration() != nullptr && prop->Declaration()->IsAnnotationDecl() &&
        memberExpr->Parent()->IsCallExpression()) {
        LogError(diagnostic::ANNOTATION_INSTANTIATION, {prop->Declaration()->Name()}, memberExpr->Start());
    }
}

std::vector<ResolveResult *> ETSChecker::HandlePropertyResolution(varbinder::LocalVariable *const prop,
                                                                  ir::MemberExpression *const memberExpr,
                                                                  varbinder::Variable *const globalFunctionVar,
                                                                  PropertySearchFlags searchFlag)
{
    std::vector<ResolveResult *> resolveRes {};

    if (prop != nullptr && IsVariableGetterSetter(prop) &&
        ((searchFlag & PropertySearchFlags::IS_GETTER) != 0 || (searchFlag & PropertySearchFlags::IS_SETTER) != 0)) {
        // SUPPRESS_CSA_NEXTLINE(alpha.core.AllocatorETSCheckerHint)
        return ValidateAccessor(memberExpr, prop, globalFunctionVar, searchFlag);
    }
    if (prop != nullptr) {
        resolveRes.emplace_back(ProgramAllocator()->New<ResolveResult>(prop, ResolvedKind::PROPERTY));
    }
    return resolveRes;
}

static bool IsClassStaticAccessTarget(const varbinder::Variable *targetRef)
{
    return targetRef != nullptr && (targetRef->HasFlag(varbinder::VariableFlags::CLASS) ||
                                    (targetRef->HasFlag(varbinder::VariableFlags::TYPE_ALIAS) &&
                                     targetRef->TsType() != nullptr && targetRef->TsType()->Variable() != nullptr &&
                                     targetRef->TsType()->Variable()->HasFlag(varbinder::VariableFlags::CLASS)));
}

static const ETSObjectType *GetStaticPropertyDeclType(const varbinder::LocalVariable *property)
{
    if (!ETSChecker::IsVariableStatic(property)) {
        return nullptr;
    }
    if (property->TsType() != nullptr && property->TsType()->IsETSMethodType()) {
        auto *funcType = property->TsType()->AsETSFunctionType();
        if (funcType->CallSignatures().empty()) {
            return nullptr;
        }
        auto *owner = funcType->CallSignatures()[0]->Owner();
        if (owner == nullptr || owner->GetDeclNode() == nullptr || !owner->GetDeclNode()->IsClassDefinition()) {
            return nullptr;
        }
        return owner;
    }

    if (property->Declaration() == nullptr || property->Declaration()->Node() == nullptr) {
        return nullptr;
    }
    auto *owner = property->Declaration()->Node()->Parent();
    if (owner == nullptr || !owner->IsClassDefinition() || owner->AsClassDefinition()->TsType() == nullptr) {
        return nullptr;
    }
    auto *ownerTsType = owner->AsClassDefinition()->TsType();
    if (ownerTsType == nullptr || !ownerTsType->IsETSObjectType()) {
        return nullptr;
    }
    return ownerTsType->AsETSObjectType();
}

static void CheckDerivedStaticMemberAccess(ETSChecker *checker, const varbinder::Variable *targetRef,
                                           const ETSObjectType *target, const varbinder::LocalVariable *prop,
                                           const ir::Identifier *ident)
{
    if (prop == nullptr || !IsClassStaticAccessTarget(targetRef) || !checker->IsVariableStatic(prop)) {
        return;
    }

    const auto *declaringType = GetStaticPropertyDeclType(prop);
    if (declaringType == nullptr || declaringType->GetDeclNode() == target->GetDeclNode()) {
        return;
    }

    checker->LogDiagnostic(diagnostic::STATIC_PROP_INVALID_CTX_DEPRECATED, {ident->Name(), declaringType},
                           ident->Start());
}

// NOLINTNEXTLINE(readability-function-size)
std::vector<ResolveResult *> ETSChecker::ResolveMemberReference(const ir::MemberExpression *const memberExpr,
                                                                ETSObjectType *const target)
{
    // SUPPRESS_CSA_NEXTLINE(alpha.core.AllocatorETSCheckerHint)
    ETSObjectTypeDeclNode(this, target);

    const auto *const targetRef = GetTargetRef(memberExpr);
    auto searchFlag = GetSearchFlags(memberExpr, targetRef);
    if (target->HasObjectFlag(ETSObjectFlags::LAZY_IMPORT_OBJECT)) {
