    if (globalFunctionVar != nullptr && !preferClassPropertyAccessor) {
        ResolvedKind resolvedKind = DecideResolvedKind(globalFunctionVar->TsType());
        if (IsExtensionAccessorCallUse(this, memberExpr, resolvedKind)) {
